-- =================================================================================
-- PHẦN 0: XÓA CÁC BẢNG CŨ NẾU ĐÃ TỒN TẠI (PHẢI XÓA THEO THỨ TỰ DO CÓ KHÓA NGOẠI)
-- =================================================================================
IF OBJECT_ID('vw_Agri_Data_Final_Merged', 'V') IS NOT NULL DROP VIEW vw_Agri_Data_Final_Merged;
IF OBJECT_ID('Process_Bangladesh_GEE_Indices_Merge', 'U') IS NOT NULL DROP TABLE Process_Bangladesh_GEE_Indices_Merge;
IF OBJECT_ID('Process_Bangladesh_soil_data_Merge', 'U') IS NOT NULL DROP TABLE Process_Bangladesh_soil_data_Merge;
IF OBJECT_ID('Process_Bangladesh_weather_data_Merge', 'U') IS NOT NULL DROP TABLE Process_Bangladesh_weather_data_Merge;
GO

-- =================================================================================
-- PHẦN 1: TẠO BẢNG VỚI KHÓA CHÍNH VÀ KHÓA NGOẠI
-- =================================================================================

-- 1. Bảng Soil Data
CREATE TABLE Process_Bangladesh_soil_data_Merge (
    District NVARCHAR(100) NOT NULL,
    pH FLOAT,
    Organic_Carbon FLOAT,
    Nitrogen FLOAT,
    Clay FLOAT,
    Silt FLOAT,
    CN_Ratio FLOAT,
    Dominant_Soil_Texture NVARCHAR(100),
    CONSTRAINT PK_Soil PRIMARY KEY (District)
);

-- 2. Bảng Weather Data
CREATE TABLE Process_Bangladesh_weather_data_Merge (
    Season NVARCHAR(50) NOT NULL,
    Rainfall FLOAT,
    Temp_Mean FLOAT,
    Temp_Max FLOAT,
    Temp_Min FLOAT,
    Heat_Stress_Days INT,
    Wind_Mean FLOAT,
    Wind_Max FLOAT,
    District NVARCHAR(100) NOT NULL,
    Year INT NOT NULL,
    Rain_Temp_Ratio FLOAT,
    CONSTRAINT PK_Weather PRIMARY KEY (District, Season, Year)
);

-- 3. Bảng GEE Indices
CREATE TABLE Process_Bangladesh_GEE_Indices_Merge (
    Area FLOAT,
    [AP Ratio] VARCHAR(50), 
    District NVARCHAR(100) NOT NULL,
    Season NVARCHAR(50) NOT NULL,
    [Avg Temp] FLOAT,
    [Avg Humidity] FLOAT,
    [Crop Name] NVARCHAR(100) NOT NULL,
    Transplant NVARCHAR(100),
    Growth NVARCHAR(100),
    Harvest NVARCHAR(100),
    Production FLOAT,
    [Max Temp] FLOAT,
    [Min Temp] FLOAT,
    [Max Relative Humidity] FLOAT,
    [Min Relative Humidity] FLOAT,
    NDVI_Season_Mean FLOAT,
    Year INT NOT NULL,
    EVI FLOAT,
    LAI FLOAT,
    FPAR FLOAT,
    LST_Kelvin FLOAT,
    Soil_Moisture_mm FLOAT,
    Avg_Salinity_Index FLOAT,
    
    CONSTRAINT PK_GEE PRIMARY KEY (District, Season, Year, [Crop Name]),
    CONSTRAINT FK_GEE_Soil FOREIGN KEY (District) REFERENCES Process_Bangladesh_soil_data_Merge(District),
    CONSTRAINT FK_GEE_Weather FOREIGN KEY (District, Season, Year) REFERENCES Process_Bangladesh_weather_data_Merge(District, Season, Year)
);
GO

