-- =================================================================================
-- PHẦN 3: TẠO VIEW GỘP DỮ LIỆU
-- =================================================================================
CREATE VIEW vw_Agri_Data_Final_Merged AS
SELECT 
    CAST(NULLIF(g.[AP Ratio], '#DIV/0!') AS FLOAT) AS [AP Ratio],
    g.District,
    g.Season,
    g.[Avg Humidity],
    g.[Crop Name],
    g.Transplant,
    g.Growth,
    g.NDVI_Season_Mean,
    g.EVI,
    g.LAI,
    g.FPAR,
    g.LST_Kelvin,
    g.Soil_Moisture_mm,
    g.Avg_Salinity_Index,
    s.pH,
    s.Organic_Carbon,
    s.Nitrogen,
    s.Clay,
    s.Silt,
    s.CN_Ratio,
    s.Dominant_Soil_Texture,
    w.Rainfall,
    w.Temp_Mean,
    w.Temp_Max,
    w.Temp_Min,
    w.Heat_Stress_Days,
    w.Wind_Mean,
    w.Wind_Max,
    w.Rain_Temp_Ratio
FROM 
    Process_Bangladesh_GEE_Indices_Merge g
LEFT JOIN 
    Process_Bangladesh_soil_data_Merge s 
    ON g.District = s.District
LEFT JOIN 
    Process_Bangladesh_weather_data_Merge w 
    ON g.District = w.District 
    AND g.Season = w.Season 
    AND g.Year = w.Year;
GO
